#include <bits/stdc++.h>
using namespace std;
int n,b[21],sum=0,ans=0;
vector<int> g[21];
deque<int> path,gpath;
void dfs(int x){
    if(g[x].size()==0){
        if(sum>ans){
            ans=sum,gpath.clear();
            for(int i=1;i<=path.size();i++){
                gpath.push_back(path.front());
                path.push_back(path.front());
                path.pop_front();
            }
        }
        return;
    }
    for(int i=0;i<g[x].size();i++){
        path.push_back(g[x][i]);
        sum+=b[g[x][i]];
        dfs(g[x][i]);
        sum-=b[g[x][i]];
        path.pop_back();
    }
}
int main(){
    cin>>n;
    for(int i=1;i<=n;i++)cin>>b[i];
    for(int i=1;i<=n;i++)g[0].push_back(i);
    for(int i=1;i<n;i++){
        for(int j=i+1;j<=n;j++){
            int k;
            cin>>k;
            if(k)g[i].push_back(j);
        }
    }
    dfs(0);
    while(!gpath.empty()){
        cout<<gpath.front()<<' ';
        gpath.pop_front();
    }
    cout<<endl<<ans;
    return 0;
}
